SELECT

FROM t_group_hongbao_log a


	a.del_flag = #{DEL_FLAG_NORMAL}
	${dataScope}

		AND a.uid = #{u.id}


		AND u.idno = #{u.idno}


		AND a.bao_id = #{baoId}


		AND a.group_id = #{group.id}


		AND `group`.idno LIKE concat('%', #{group.idno}, '%')




		ORDER BY ${page.orderBy}


		ORDER BY a.create_date DESC

SELECT

FROM t_group_hongbao_log a


	a.del_flag = #{DEL_FLAG_NORMAL}
	${dataScope}

		AND a.uid = #{u.id}


		AND u.idno = #{u.idno}


		AND a.bao_id = #{baoId}


		AND a.group_id = #{group.id}


		AND `group`.idno LIKE concat('%', #{group.idno}, '%')




		ORDER BY ${page.orderBy}


		ORDER BY a.update_date DESC

